const parseSegment = (segment: string, config: FieldConfig): number[] => {
  const { min, max } = config;

  // Wildcard with optional step: * or */n
  if (segment.startsWith("*")) {
    if (segment === "*") return range(min, max);
    const stepMatch = segment.match(/^\*\/(\d+)$/);
    if (!stepMatch) throw new Error(`Invalid step expression: ${segment}`);
    const step = parseInt(stepMatch[1], 10);
    if (step < 1) throw new Error(`Step must be >= 1, got: ${step}`);
    return range(min, max, step);
  }

  // Range with optional step: n-m or n-m/s
  if (segment.includes("-")) {
    const rangeStepMatch = segment.match(/^(\d+)-(\d+)(?:\/(\d+))?$/);
    if (!rangeStepMatch) throw new Error(`Invalid range expression: ${segment}`);
    const start = parseInt(rangeStepMatch[1], 10);
    const end   = parseInt(rangeStepMatch[2], 10);
    const step  = rangeStepMatch[3] ? parseInt(rangeStepMatch[3], 10) : 1;
    if (start < min || end > max) throw new Error(`Range ${start}-${end} out of bounds [${min}-${max}]`);
    if (start > end) throw new Error(`Range start ${start} > end ${end}`);
    if (step < 1) throw new Error(`Step must be >= 1, got: ${step}`);
    return range(start, end, step);
  }

  // Comma-separated list: n,m,o,...
  if (segment.includes(",")) {
    const values = segment.split(",").map((v) => {
      const n = parseInt(v.trim(), 10);
      if (isNaN(n)) throw new Error(`Invalid value in list: ${v}`);
      if (n < min || n > max) throw new Error(`Value ${n} out of bounds [${min}-${max}]`);
      return n;
    });
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Single number
  const n = parseInt(segment, 10);
  if (isNaN(n)) throw new Error(`Invalid cron field value: ${segment}`);
  if (n < min || n > max) throw new Error(`Value ${n} out of bounds [${min}-${max}]`);
  return [n];
};

