    )].sort((a, b) => a - b);
  }

  // Step value: */n or start-end/n
  if (expr.includes("/")) {
    const [rangePart, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new SyntaxError(`Invalid step value: ${stepStr}`);

    let base: number[];
    if (rangePart === "*") {
      base = expandRange(min, max);
    } else if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      const start = clamp(parseInt(startStr, 10));
      const end   = clamp(parseInt(endStr,   10));
      if (start > end) throw new RangeError(`Invalid range: ${rangePart}`);
      base = expandRange(start, end);
    } else {
      const start = clamp(parseInt(rangePart, 10));
      base = expandRange(start, max);
    }

    return base.filter(v => (v - base[0]) % step === 0);
  }

  // Range: start-end
  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = clamp(parseInt(startStr, 10));
    const end   = clamp(parseInt(endStr,   10));
    if (start > end) throw new RangeError(`Invalid range: ${expr}`);
    return expandRange(start, end);
  }

  // Wildcard
  if (expr === "*") {
    return expandRange(min, max);
  }

  // Single number
  const n = parseInt(expr, 10);
  if (isNaN(n)) throw new SyntaxError(`Invalid cron field value: ${expr}`);
  return [clamp(n)];
}

export default function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(
      `Expected 5 cron fields, got ${parts.length}: "${expression}"`
    );
  }

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];

  return fieldNames.reduce((acc, field, i) => {
    const [min, max] = FIELD_RANGES[field];
    acc[field] = parseField(parts[i], min, max);
    return acc;
  }, {} as CronFields);
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute:     [0, 59],
  hour:       [0, 23],
  dayOfMonth: [1, 31],
  month:      [1, 12],
  dayOfWeek:  [0,  6],
};

function expandRange(min: number, max: number): number[] {
  return Array.from({ length: max - min + 1 }, (_, i) => min + i);
}

function parseField(expr: string, fieldMin: number, fieldMax: number): number[] {
  // Comma-separated list — recurse on each part
  if (expr.includes(",")) {
    const values = expr
      .split(",")
      .flatMap((part) => parseField(part.trim(), fieldMin, fieldMax));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard
  if (expr === "*") {
    return expandRange(fieldMin, fieldMax);
  }

  // Step value: */n or start/n
  if (expr.includes("/")) {
    const [rangeExpr, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new RangeError(`Invalid step value: "${stepStr}"`);
    }
    const base = rangeExpr === "*" ? expandRange(fieldMin, fieldMax) : parseField(rangeExpr, fieldMin, fieldMax);
    return base.filter((v) => (v - base[0]) % step === 0);
  }

  // Range: start-end
  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = parseInt(startStr, 10);
    const end   = parseInt(endStr,   10);
    if (isNaN(start) || isNaN(end)) {
      throw new RangeError(`Invalid range: "${expr}"`);
    }
    if (start < fieldMin || end > fieldMax || start > end) {
      throw new RangeError(
        `Range "${expr}" is out of bounds [${fieldMin}, ${fieldMax}]`
      );
    }
    return expandRange(start, end);
  }

  // Single number
  const n = parseInt(expr, 10);
  if (isNaN(n)) {
    throw new TypeError(`Invalid cron field value: "${expr}"`);
  }
  if (n < fieldMin || n > fieldMax) {
    throw new RangeError(
      `Value ${n} is out of bounds [${fieldMin}, ${fieldMax}]`
    );
  }
  return [n];
}

export default function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `Expected 5 cron fields, got ${parts.length}: "${expression}"`
    );
  }

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];
  const result = {} as CronFields;

  for (let i = 0; i < fieldNames.length; i++) {
    const field = fieldNames[i];
    const [min, max] = FIELD_RANGES[field];
    result[field] = parseField(parts[i], min, max);
  }

  return result;
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: Record<keyof CronExpression, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function range(start: number, end: number): number[] {
  if (start > end) throw new RangeError(`Invalid range: ${start}-${end}`);
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function clamp(values: number[], min: number, max: number): number[] {
  const invalid = values.filter(v => v < min || v > max);
  if (invalid.length > 0) {
    throw new RangeError(`Values out of range [${min}-${max}]: ${invalid.join(", ")}`);
  }
  return [...new Set(values)].sort((a, b) => a - b);
}

function parseField(expr: string, config: FieldConfig): number[] {
  const { min, max } = config;
  const full = range(min, max);

  // Comma-separated list — recurse on each part
  if (expr.includes(",")) {
    const values = expr
      .split(",")
      .flatMap(part => parseField(part.trim(), config));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard with optional step: * or */N
  if (expr.startsWith("*")) {
    if (expr === "*") return full;
    const stepMatch = expr.match(/^\*\/(\d+)$/);
    if (!stepMatch) throw new SyntaxError(`Invalid expression: "${expr}"`);
    const step = parseInt(stepMatch[1], 10);
    if (step <= 0) throw new RangeError(`Step must be >= 1, got ${step}`);
    return full.filter(v => (v - min) % step === 0);
  }

  // Range with optional step: N-M or N-M/S
  if (expr.includes("-")) {
    const rangeStepMatch = expr.match(/^(\d+)-(\d+)(?:\/(\d+))?$/);
    if (!rangeStepMatch) throw new SyntaxError(`Invalid expression: "${expr}"`);
    const start = parseInt(rangeStepMatch[1], 10);
    const end   = parseInt(rangeStepMatch[2], 10);
    const step  = rangeStepMatch[3] ? parseInt(rangeStepMatch[3], 10) : 1;
    if (step <= 0) throw new RangeError(`Step must be >= 1, got ${step}`);
    const values = range(start, end).filter((_, i) => i % step === 0);
    return clamp(values, min, max);
  }

  // Single number
  const num = parseInt(expr, 10);
  if (isNaN(num)) throw new SyntaxError(`Invalid token: "${expr}"`);
  return clamp([num], min, max);
}

export default function parseCron(expression: string): CronExpression {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts;
  const fields = Object.keys(FIELD_CONFIGS) as Array<keyof CronExpression>;
  const exprs  = [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr];

  return fields.reduce((acc, field, i) => {
    acc[field] = parseField(exprs[i], FIELD_CONFIGS[field]);
    return acc;
  }, {} as CronExpression);
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(expr: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];

  if (expr === "*") return range(min, max);

  if (expr.includes(",")) {
    return expr
      .split(",")
      .flatMap((part) => parseField(part.trim(), field))
      .filter((v, i, arr) => arr.indexOf(v) === i)
      .sort((a, b) => a - b);
  }

  if (expr.startsWith("*/")) {
    const step = parseInt(expr.slice(2), 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step in field "${field}": ${expr}`);
    const result: number[] = [];
    for (let i = min; i <= max; i += step) result.push(i);
    return result;
  }

  if (expr.includes("/")) {
    const [rangePart, stepPart] = expr.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step in field "${field}": ${expr}`);
    const [rangeStart, rangeEnd] = rangePart.includes("-")
      ? rangePart.split("-").map((n) => parseInt(n, 10))
      : [parseInt(rangePart, 10), max];
    if (isNaN(rangeStart) || isNaN(rangeEnd)) throw new Error(`Invalid range in field "${field}": ${expr}`);
    validateRange(rangeStart, rangeEnd, min, max, field);
    const result: number[] = [];
    for (let i = rangeStart; i <= rangeEnd; i += step) result.push(i);
    return result;
  }

  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range in field "${field}": ${expr}`);
    validateRange(start, end, min, max, field);
    if (start > end) throw new Error(`Range start > end in field "${field}": ${expr}`);
    return range(start, end);
  }

  const value = parseInt(expr, 10);
  if (isNaN(value)) throw new Error(`Invalid value in field "${field}": ${expr}`);
  if (value < min || value > max) throw new Error(`Value ${value} out of range [${min}, ${max}] for field "${field}"`);
  return [value];
}

function validateRange(start: number, end: number, min: number, max: number, field: CronField): void {
  if (start < min || end > max) {
    throw new Error(`Range [${start}-${end}] out of bounds [${min}-${max}] for field "${field}"`);
  }
}

export default function parseCron(expression: string): CronResult {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(`Expected 5 fields, got ${parts.length}: "${expression}"`);
  }

  const fields: CronField[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];
  const result = {} as CronResult;

  for (let i = 0; i < fields.length; i++) {
    result[fields[i]] = parseField(parts[i], fields[i]);
  }

  return result;
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   6],
};

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function parseField(expr: string, min: number, max: number): number[] {
  const results = new Set<number>();

  for (const part of expr.split(",")) {
    const trimmed = part.trim();

    // Step: */n or a-b/n
    if (trimmed.includes("/")) {
      const [rangePart, stepStr] = trimmed.split("/");
      const step = parseInt(stepStr, 10);
      if (isNaN(step) || step <= 0) {
        throw new SyntaxError(`Invalid step value: "${stepStr}"`);
      }

      let rangeMin = min;
      let rangeMax = max;

      if (rangePart !== "*") {
        if (rangePart.includes("-")) {
          const [lo, hi] = rangePart.split("-").map(s => parseInt(s, 10));
          rangeMin = clamp(lo, min, max);
          rangeMax = clamp(hi, min, max);
        } else {
          rangeMin = clamp(parseInt(rangePart, 10), min, max);
        }
      }

      for (let i = rangeMin; i <= rangeMax; i += step) {
        results.add(i);
      }
      continue;
    }

    // Wildcard
    if (trimmed === "*") {
      for (let i = min; i <= max; i++) results.add(i);
      continue;
    }

    // Range: a-b
    if (trimmed.includes("-")) {
      const [lo, hi] = trimmed.split("-").map(s => parseInt(s, 10));
      const start = clamp(lo, min, max);
      const end = clamp(hi, min, max);
      if (start > end) {
        throw new RangeError(`Invalid range: ${start}-${end}`);
      }
      for (let i = start; i <= end; i++) results.add(i);
      continue;
    }

    // Literal number
    const num = parseInt(trimmed, 10);
    if (isNaN(num)) {
      throw new SyntaxError(`Invalid cron token: "${trimmed}"`);
    }
    results.add(clamp(num, min, max));
  }

  return Array.from(results).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields but got ${parts.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts;
  const fields = Object.keys(FIELD_RANGES) as (keyof CronFields)[];

  const [minute, hour, dayOfMonth, month, dayOfWeek] = [
    minuteExpr, hourExpr, domExpr, monthExpr, dowExpr,
  ].map((expr, i) => {
    const field = fields[i];
    const [min, max] = FIELD_RANGES[field];
    try {
      return parseField(expr, min, max);
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      throw new Error(`Invalid "${field}" field ("${expr}"): ${msg}`);
    }
  });

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}
